"use client";
import { useRef } from "react";
import Link from "next/link";
import { motion, useInView } from "framer-motion";
import { games } from "@/lib/data/games";
import { Gamepad2, Monitor, Smartphone, Globe, Car, Swords, Joystick, Rocket } from "lucide-react";

const artworkIcons = [Car, Swords, Joystick, Rocket];

const platformIcons: Record<string, React.ReactNode> = {
  PC: <Monitor size={12} />,
  Mobile: <Smartphone size={12} />,
  Console: <Gamepad2 size={12} />,
  Web: <Globe size={12} />,
};

const statusColors: Record<string, string> = {
  Released: "text-green-400 bg-green-400/10 border-green-400/20",
  "In Development": "text-fluke-yellow bg-fluke-yellow/10 border-fluke-yellow/20",
  "Coming Soon": "text-purple-400 bg-purple-400/10 border-purple-400/20",
};

export default function GamesShowcase() {
  const ref = useRef<HTMLDivElement>(null);
  const isInView = useInView(ref, { once: true, margin: "-100px" });

  return (
    <section className="py-32 bg-fluke-bg overflow-hidden" ref={ref}>
      <div className="max-w-7xl mx-auto px-6 mb-12">
        <motion.div
          initial={{ opacity: 0, y: 30 }}
          animate={isInView ? { opacity: 1, y: 0 } : {}}
          transition={{ duration: 0.7 }}
        >
          <p className="font-orbitron text-xs tracking-[0.4em] text-fluke-yellow uppercase mb-3">
            Our Worlds
          </p>
          <h2 className="font-bebas text-5xl sm:text-7xl text-fluke-text yellow-line">
            Games We&apos;ve Built
          </h2>
        </motion.div>
      </div>

      {/* Horizontal scroll area */}
      <div className="horizontal-scroll flex gap-6 px-6 pb-6 md:px-10">
        {games.map((game, i) => (
          <motion.div
            key={game.id}
            initial={{ opacity: 0, x: 60 }}
            animate={isInView ? { opacity: 1, x: 0 } : {}}
            transition={{ duration: 0.6, delay: i * 0.1 }}
            className="flex-none w-72 md:w-80"
          >
            <Link href={`/games/${game.slug}`}>
              <div className="group relative rounded-3xl overflow-hidden bg-[#0c0c0c] border border-fluke-yellow/10 transition-all duration-500 hover:-translate-y-2 hover:shadow-[0_20px_60px_rgba(245,197,66,0.15)] h-[420px] isolate">
                {/* Game art placeholder - image background */}
                <div className="absolute inset-0 z-0">
                  <div
                    className="w-full h-full transition-transform duration-700 ease-out group-hover:scale-110 flex items-center justify-center opacity-30 group-hover:opacity-40"
                    style={{
                      background: `linear-gradient(135deg, hsl(${i * 60 + 20}, 40%, 15%) 0%, hsl(${i * 60}, 50%, 8%) 100%)`,
                    }}
                  >
                      {(() => {
                        const Icon = artworkIcons[i % 4];
                        return <Icon size={120} strokeWidth={0.5} className="text-fluke-yellow/40 mix-blend-overlay" />;
                      })()}
                  </div>
                  {/* Atmospheric overlay */}
                  <div className="absolute inset-0 bg-gradient-to-t from-[#0c0c0c] via-[#0c0c0c]/80 to-transparent z-10" />
                </div>

                {/* Card content */}
                <div className="absolute inset-0 z-20 p-6 sm:p-8 flex flex-col justify-end">
                  {/* Status Badge */}
                  <div className="absolute top-6 left-6">
                    <span className={`text-[10px] font-orbitron tracking-widest uppercase px-3 py-1 rounded-full border backdrop-blur-md ${statusColors[game.status]}`}>
                      {game.status}
                    </span>
                  </div>

                  <div className="transform transition-transform duration-500 translate-y-4 group-hover:translate-y-0">
                    <div className="flex items-center gap-3 mb-3">
                      <span className="font-orbitron text-xs text-fluke-yellow tracking-widest uppercase">
                        {game.genre}
                      </span>
                      <span className="w-1 h-1 rounded-full bg-fluke-muted/40" />
                      <span className="font-sora text-xs text-fluke-muted">{game.releaseYear}</span>
                    </div>
                    
                    <h3 className="font-bebas text-4xl text-fluke-text group-hover:text-fluke-white transition-colors mb-3 tracking-wide">
                      {game.title}
                    </h3>
                    
                    <p className="font-sora text-sm text-fluke-muted line-clamp-2 mb-6 opacity-0 group-hover:opacity-100 transition-opacity duration-500 delay-100">
                      {game.description}
                    </p>
                    
                    {/* Platforms */}
                    <div className="flex gap-2 items-center">
                      <div className="text-xs font-sora text-fluke-muted mr-2">Platforms:</div>
                      {game.platforms.map((p) => (
                        <span
                          key={p}
                          title={p}
                          className="flex items-center justify-center w-8 h-8 text-fluke-muted/80 bg-white/5 hover:bg-white/10 hover:text-fluke-yellow border border-white/5 rounded-full backdrop-blur-sm transition-all"
                        >
                          {platformIcons[p]}
                        </span>
                      ))}
                    </div>
                  </div>
                </div>

                {/* Hover glow border */}
                <div className="absolute inset-0 rounded-3xl opacity-0 group-hover:opacity-100 transition-opacity duration-500 pointer-events-none border-2 border-fluke-yellow/30 z-30" />
              </div>
            </Link>
          </motion.div>
        ))}

        {/* View all card */}
        <motion.div
          initial={{ opacity: 0, x: 60 }}
          animate={isInView ? { opacity: 1, x: 0 } : {}}
          transition={{ duration: 0.6, delay: games.length * 0.1 }}
          className="flex-none w-72 md:w-80"
        >
          <Link href="/games">
            <div className="h-96 rounded-2xl border border-dashed border-fluke-yellow/20 flex flex-col items-center justify-center gap-4 hover:border-fluke-yellow/50 hover:bg-fluke-yellow/5 transition-all duration-300 group">
              <div className="w-16 h-16 rounded-full border border-fluke-yellow/30 flex items-center justify-center group-hover:border-fluke-yellow/60 transition-colors">
                <Gamepad2 size={28} className="text-fluke-yellow/60 group-hover:text-fluke-yellow transition-colors" />
              </div>
              <p className="font-orbitron text-sm text-fluke-muted group-hover:text-fluke-yellow transition-colors">
                View All Games
              </p>
            </div>
          </Link>
        </motion.div>
      </div>
    </section>
  );
}
