"use client";
import { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import Image from "next/image";

export default function IntroScreen({ onComplete }: { onComplete: () => void }) {
  const [phase, setPhase] = useState(0);

  useEffect(() => {
    const t1 = setTimeout(() => setPhase(1), 400);   // logo appears
    const t2 = setTimeout(() => setPhase(2), 1200);  // glow pulse
    const t3 = setTimeout(() => setPhase(3), 2000);  // fade out
    const t4 = setTimeout(() => onComplete(), 2600); // done
    return () => { clearTimeout(t1); clearTimeout(t2); clearTimeout(t3); clearTimeout(t4); };
  }, [onComplete]);

  return (
    <AnimatePresence>
      {phase < 3 && (
        <motion.div
          key="intro"
          initial={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          transition={{ duration: 0.6 }}
          className="fixed inset-0 z-[99999] bg-fluke-bg flex flex-col items-center justify-center"
        >
          {/* Logo */}
          <motion.div
            initial={{ opacity: 0, scale: 0.5 }}
            animate={phase >= 1 ? { opacity: 1, scale: 1 } : {}}
            transition={{ duration: 0.7, ease: "easeOut" }}
            className="relative w-32 h-32 mb-6"
          >
            <Image
              src="/logo.png"
              alt="Fluke"
              fill
              className="object-contain"
              priority
              style={{
                filter: phase >= 2 ? "drop-shadow(0 0 30px #F5C542) drop-shadow(0 0 60px #F5C54288)" : "none",
                transition: "filter 0.8s ease",
              }}
            />
          </motion.div>

          {/* Studio name */}
          <motion.p
            initial={{ opacity: 0, y: 10 }}
            animate={phase >= 1 ? { opacity: 1, y: 0 } : {}}
            transition={{ duration: 0.6, delay: 0.3 }}
            className="font-orbitron text-sm tracking-[0.5em] text-fluke-yellow/80 uppercase"
          >
            Fluke Game Studio
          </motion.p>

          {/* Controller button hints */}
          <motion.div
            initial={{ opacity: 0 }}
            animate={phase >= 2 ? { opacity: 1 } : {}}
            transition={{ duration: 0.6 }}
            className="flex gap-5 mt-8"
          >
            {["⬆", "⬇", "◀", "▶"].map((btn, i) => (
              <motion.span
                key={i}
                initial={{ opacity: 0 }}
                animate={{ opacity: [0, 1, 0.4] }}
                transition={{ duration: 0.5, delay: i * 0.12, repeat: 1 }}
                className="text-fluke-yellow/60 text-lg"
                style={{ textShadow: "0 0 8px #F5C542" }}
              >
                {btn}
              </motion.span>
            ))}
          </motion.div>

          {/* Loading bar */}
          <motion.div
            initial={{ width: 0 }}
            animate={{ width: "160px" }}
            transition={{ duration: 2, ease: "easeInOut" }}
            className="mt-10 h-px bg-fluke-yellow/60 rounded-full"
            style={{ boxShadow: "0 0 8px #F5C542" }}
          />
        </motion.div>
      )}
    </AnimatePresence>
  );
}
